 The behavior is, for all semantic purposes, identical. Thank you ReactOS team :)So what&#39;s the deal with the TEB and TIB?WELL, I&#39;m glad you asked.Let&#39;s take the two instructions from the disassembly and check to see what offsets they&#39;re referencing. (rdi == TEB)
 00007ffc`cdd58252 66838fee17000004 or word ptr [rdi+17EEh], 4; Setting the Teb-&gt;HasFiberData flag to True 00007ffc`cdd5825a 48895720 mov qword ptr [rdi+20h], rdx; Setting Teb-&gt;FiberData
 Examining the TEB structure, we find that the WORD referenced by  *(rdi+0x17ee) actually represents bit flags for different features in the process.
 0:000&gt; dt nt!_TEBntdll!_TEB +0x17ee SameTebFlags : Uint2B +0x17ee SafeThunkCall : Pos 0, 1 Bit +0x17ee InDebugPrint : Pos 1, 1 Bit  +0x17ee HasFiberData : Pos 2, 1 Bit ; &#34;or word ptr [rdi+17EEh], 4&#34; sets this to TRUE +0x17ee SkipThreadAttach : Pos 3, 1 Bit +0x17ee WerInShipAssertCode : Pos 4, 1 Bit +0x17ee RanProcessInit : Pos 5, 1 Bit +0x17ee ClonedThread : Pos 6, 1 Bit +0x17ee SuppressDebugMsg : Pos 7, 1 Bit +0x17ee DisableUserStackWalk : Pos 8, 1 Bit +0x17ee RtlExceptionAttached : Pos 9, 1 Bit +0x17ee InitialThread : Pos 10, 1 Bit +0x17ee SessionAware : Pos 11, 1 Bit +0x17ee LoadOwner : Pos 12, 1 Bit +0x17ee LoaderWorker : Pos 13, 1 Bit +0x17ee SkipLoaderInit : Pos 14, 1 Bit +0x17ee SpareSameTebBits : Pos 15, 1 Bit
 We can also see that the  QWORD PTR referenced by  *(rdi+0x20) is a FiberData pointer in the process&#39; TIB.
 0:000&gt; dt nt!_NT_TIBntdll!_NT_TIB +0x000 ExceptionList : Ptr64 _EXCEPTION_REGISTRATION_RECORD +0x008 StackBase : Ptr64 Void +0x010 StackLimit : Ptr64 Void +0x018 SubSystemTib : Ptr64 Void  +0x020 FiberData : Ptr64 Void ; This is what GetFiberData fetches +0x020 Version : Uint4B +0x028 ArbitraryUserPointer : Ptr64 Void +0x030 Self : Ptr64 _NT_TIB
 Neat. So our FiberData pointer and HasFiberData flag both live in the TEB.One could define a GetFiberData macro essentially as a few intrinsic functions equivalent to:
 void* GetFiberData(){ #ifdef _WIN64 return __readgsqword(0x20) // mov rax, gs:[20] #else return __readfsdword(0x20) // mov eax, fs:[20] #endif}
 So how does CreateFiber store the instruction pointer of the function we desire?Let&#39;s again go back to ReactOS for definition of  CreateFiberEx (this time without truncation):
 /** @implemented*/LPVOIDWINAPICreateFiberEx(_In_ SIZE_T dwStackCommitSize, _In_ SIZE_T dwStackReserveSize, _In_ DWORD dwFlags, _In_ LPFIBER_START_ROUTINE lpStartAddress, _In_opt_ LPVOID lpParameter){  PFIBER Fiber; !! Note this NTSTATUS Status; INITIAL_TEB InitialTeb; PACTIVATION_CONTEXT_STACK ActivationContextStackPointer; DPRINT(&#34;Creating Fiber\n&#34;); /* Check for invalid flags */ if (dwFlags &amp; ~FIBER_FLAG_FLOAT_SWITCH) { /* Fail */ SetLastError(ERROR_INVALID_PARAMETER); return NULL; } /* Allocate the Activation Context Stack */ ActivationContextStackPointer = NULL; Status = RtlAllocateActivationContextStack(&amp;ActivationContextStackPointer); if (!NT_SUCCESS(Status)) { /* Fail */ BaseSetLastNTError(Status); return NULL; } /* Allocate the fiber */ Fiber = RtlAllocateHeap(RtlGetProcessHeap(), 0, sizeof(FIBER)); if (!Fiber) { /* Free the activation context stack */ RtlFreeActivationContextStack(ActivationContextStackPointer); /* Fail */ SetLastError(ERROR_NOT_ENOUGH_MEMORY); return NULL; } /* Create the stack for the fiber */ Status = BaseCreateStack(NtCurrentProcess(), dwStackCommitSize, dwStackReserveSize, &amp;InitialTeb); if (!NT_SUCCESS(Status)) { /* Free the fiber */ RtlFreeHeap(GetProcessHeap(), 0, Fiber); /* Free the activation context stack */ RtlFreeActivationContextStack(ActivationContextStackPointer); /* Failure */ BaseSetLastNTError(Status); return NULL; } /* Clear the context */ RtlZeroMemory(&amp;Fiber-&gt;FiberContext, sizeof(CONTEXT)); /* Copy the data into the fiber */ Fiber-&gt;StackBase = InitialTeb.StackBase; Fiber-&gt;StackLimit = InitialTeb.StackLimit; Fiber-&gt;DeallocationStack = InitialTeb.AllocatedStackBase; Fiber-&gt;FiberData = lpParameter; Fiber-&gt;ExceptionList = EXCEPTION_CHAIN_END; Fiber-&gt;GuaranteedStackBytes = 0; Fiber-&gt;FlsData = NULL; Fiber-&gt;ActivationContextStackPointer = ActivationContextStackPointer; /* Save FPU State if requested, otherwise just the basic registers */ Fiber-&gt;FiberContext.ContextFlags = (dwFlags &amp; FIBER_FLAG_FLOAT_SWITCH) ? (CONTEXT_FULL | CONTEXT_FLOATING_POINT) : CONTEXT_FULL; /* Initialize the context for the fiber */ BaseInitializeContext( &amp;Fiber-&gt;FiberContext, // AHA! We found the CONTEXT we were looking for! lpParameter,  lpStartAddress InitialTeb.StackBase, 2); /* Return the Fiber */ return Fiber;}
